import React from "react";
import { makeStyles, Theme } from "@material-ui/core/styles";
import Tabs from "@material-ui/core/Tabs";
import Tab from "@material-ui/core/Tab";
import WorkOutlineIcon from '@material-ui/icons/WorkOutline';
import BuildIcon from '@material-ui/icons/Build';
import LocationOnIcon from '@material-ui/icons/LocationOn';
import FavoriteBorderIcon from '@material-ui/icons/FavoriteBorder';
import FilterVintageIcon from '@material-ui/icons/FilterVintage';
import Box from "@material-ui/core/Box";

import Aboutme from "./Aboutme";
import TechnicalStack from "./TechnicalStack";
import WorkHistory from "./WorkHistory";
import Contactus from "./Contactus";
import DesignPatternsTab from "./designpatterns/DesignPatternsTab";

interface TabPanelProps {
	children?: React.ReactNode;
	index: any;
	value: any;
}

function TabPanel(props: TabPanelProps) {
	const { children, value, index, ...other } = props;

	return (
		<div
			role="tabpanel"
			hidden={value !== index}
			id={`scrollable-force-tabpanel-${index}`}
			aria-labelledby={`scrollable-force-tab-${index}`}
			{...other}
		>
			{value === index ? (
				<Box p={3}>
					{children}
				</Box>
			) : ""}
		</div>
	);
}

function a11yProps(index: any) {
	return {
		id: `scrollable-force-tab-${index}`,
		"aria-controls": `scrollable-force-tabpanel-${index}`,
	};
}

const useStyles = makeStyles((theme: Theme) => ({
	root: {
		flexGrow: 1,
		width: "100%",
		backgroundColor: theme.palette.background.paper,
	},
	tabWidth: {
	}
}));

export default function TabMain() {
	const classes = useStyles();
	const [value, setValue] = React.useState(0);

	const handleChange = (event: React.ChangeEvent<{}>, newValue: number) => {
		setValue(newValue);
	};

	return (
		<div className={classes.root}>
			<Tabs
				value={value}
				onChange={handleChange}
				variant="scrollable"
				scrollButtons="on"
				indicatorColor="secondary"
				textColor="primary"
				aria-label="tabmain"
			>
				<Tab label="About me" icon={<FavoriteBorderIcon />} {...a11yProps(1)}
					className={classes.tabWidth} />
				<Tab label="Technical stack" icon={<BuildIcon />} {...a11yProps(2)}
					className={classes.tabWidth} />
				<Tab label="Work History" icon={<WorkOutlineIcon />} {...a11yProps(3)}
					className={classes.tabWidth} />
				<Tab label="Design Patterns" icon={<FilterVintageIcon />} {...a11yProps(4)}
					className={classes.tabWidth} />
				<Tab label="Contact" icon={<LocationOnIcon />} {...a11yProps(4)}
					className={classes.tabWidth} />
			</Tabs>

			<TabPanel value={value} index={0}>
				<Aboutme />
			</TabPanel>
			<TabPanel value={value} index={1}>
				<TechnicalStack />
			</TabPanel>
			<TabPanel value={value} index={2}>
				<WorkHistory />
			</TabPanel>
			<TabPanel value={value} index={3}>
				<DesignPatternsTab />
			</TabPanel>
			<TabPanel value={value} index={4}>
				<Contactus />
			</TabPanel>
		</div>
	);
}
